async function load<T>(path:string):Promise<T>{return JSON.parse(await readFile(path,"utf8")) as T;}
async function save(path:string,data:unknown){await writeFile(path,JSON.stringify(data,null,2));}
function hashPassword(password:string,salt=randomBytes(16).toString("hex")){return `${salt}:${scryptSync(password,salt,64).toString("hex")}`;}
function verifyPassword(password:string,stored:string){const [salt,hash]=stored.split(":");if(!salt||!hash)return false;const actual=scryptSync(password,salt,64),expected=Buffer.from(hash,"hex");return actual.length===expected.length&&timingSafeEqual(actual,expected);}
function tokenFor(user:UserRecord){const payload=Buffer.from(JSON.stringify({id:user.id,email:user.email,name:user.name,role:user.role,exp:Date.now()+7*864e5})).toString("base64url");const signature=createHmac("sha256",sessionSecret).update(payload).digest("base64url");return `${payload}.${signature}`;}
function userFrom(header?:string){try{const [payload,signature]=(header?.replace(/^Bearer /,"")||"").split(".");const actual=createHmac("sha256",sessionSecret).update(payload).digest();const expected=Buffer.from(signature,"base64url");if(actual.length!==expected.length||!timingSafeEqual(actual,expected))return null;const user=JSON.parse(Buffer.from(payload,"base64url").toString()) as {id:string;email:string;name:string;role:string;exp:number};return user.exp>Date.now()?user:null;}catch{return null;}}
async function authenticatedUser(header?:string){
  if(!isSupabaseConfigured()){const tokenUser=userFrom(header);if(!tokenUser)return null;const users=await load<UserRecord[]>(usersFile);const user=users.find(item=>item.id===tokenUser.id);return user?{id:user.id,email:user.email,name:user.name,role:user.role,avatar:user.avatar,createdAt:user.createdAt,exp:tokenUser.exp}:null;}
  const accessToken=header?.replace(/^Bearer /,"");if(!accessToken)return null;
  const authUser=await getSupabaseUser(accessToken);if(!authUser)return null;
  const profile=await getSupabaseProfile(authUser.id);if(!profile)return null;
  return {id:authUser.id,email:authUser.email||"",name:profile.display_name,role:profile.role,avatar:profile.avatar_url,createdAt:profile.created_at,exp:Number.MAX_SAFE_INTEGER};
}

